text:
&-load-more {
  display: flex;
  justify-content: center;
  align-items: center;
  background: @color-fill-grey-inverse;
  background: var(--am-list-background, @color-fill-grey-inverse);
  padding: @v-spacing-large;
  padding: var(--am-list-load-padding, @v-spacing-large);
  font-size: @font-size-subtitle;
  font-size: var(--am-list-load-fontSize, @font-size-subtitle);
  line-height: @line-height-paragraph;
  line-height: var(--am-list-load-lineHeight, @line-height-paragraph);
  color: @color-fill-grey-dark;
  color: var(--am-list-load-more-color, @color-fill-grey-dark);
  &-txt {
    padding: 0 @h-spacing-standard;
    padding: 0 var(--am-list-load-txt-paddingLR, @h-spacing-standard);
    color: @color-text-subtitle;
    color: var(--am-list-load-txt-color, @color-text-subtitle);
  }
}

&-inner {
    display: inline-block;
    width: 14px;
    height: 14px;
    position: relative;
    top: 0;
    left: 0;
    border: 1px solid @border-color-base;
    border-radius: 2px;
    background-color: #fff;
    transition: border-color @transition-time @ease-in-out, background-color @transition-time @ease-in-out, box-shadow @transition-time @ease-in-out;

    &:after {
        content: '';
        display: table;
        width: 4px;
        height: 8px;
        position: absolute;
        top: 1px;
        left: 4px;
        border: 2px solid #fff;
        border-top: 0;
        border-left: 0;
        transform: rotate(45deg) scale(0);
        transition: all @transition-time @ease-in-out;
    }
}

&-trigger {
    position: absolute;
    top: @layout-header-height;
    right: -@layout-zero-trigger-width;
    text-align: center;
    width: @layout-zero-trigger-width;
    height: @layout-zero-trigger-height;
    line-height: @layout-zero-trigger-height;
    background: @layout-sider-background;
    color: #fff;
    font-size: @layout-zero-trigger-width / 2;
    border-radius: 0 @border-radius-base @border-radius-base 0;
    cursor: pointer;
    transition: background .3s ease;

    &:hover {
      background: tint(@layout-sider-background, 10%);
    }

    &&-left {
        right: 0;
        left: -@layout-zero-trigger-width;
        border-radius: @border-radius-base 0 0 @border-radius-base;
    }
}

> tr {
  > th {
    position: relative;
    color: @table-header-color;
    font-weight: 500;
    text-align: left;
    background: @table-header-bg;
    border-bottom: @border-width-base @border-style-base @table-border-color;
    transition: background 0.3s ease;

    &[colspan]:not([colspan='1']) {
      text-align: center;
    }

    &:not(:last-child):not(.@{table-prefix-cls}-selection-column):not(.@{table-prefix-cls}-row-expand-icon-cell):not([colspan])::before {
      position: absolute;
      top: 50%;
      right: 0;
      width: 1px;
      height: 1.6em;
      background-color: @table-header-cell-split-color;
      transform: translateY(-50%);
      transition: background-color 0.3s;
      content: '';
    }
  }
}

&__body {
  position: relative;
  height: var(--tv-Transfer-panel-body-height);
  overflow: auto;
  text-align: left;
  padding-right: var(--tv-Transfer-panel-body-padding-right);
  padding-left: var(--tv-Transfer-panel-body-padding-left);
  display: flex;
  flex-direction: column;

  .tiny-table.simple table tbody tr:has(td svg.is-check) {
    background-color: var(--tv-Transfer-panel-item-active-bg-color);
  }

  .@{tree-prefix-cls} {
    height: var(--tv-Transfer-panel-body-tree-height);
    padding-left: var(--tv-Transfer-panel-body-tree-padding-left);
    padding-right: var(--tv-Transfer-panel-body-tree-padding-right);
    padding-top: var(--tv-Transfer-panel-body-tree-padding-top);
    padding-bottom: var(--tv-Transfer-panel-body-tree-padding-bottom);
    overflow: auto;
    .transfer-scrollbar(8px);
  }

  .@{transfer-panel-prefix-cls}__filter ~ .@{tree-prefix-cls} {
    height: var(--tv-Transfer-panel-body-tree-filter-height);
  }
}

&:active {
  & when (@border = transparent) {
    & when (@theme = dark) {
      .button-color(colorPalette('@{color}', 5); null; transparent);
    }
    & when (not (@theme = dark) and not (@theme = variable)) {
      .button-color(colorPalette('@{color}', 7); null; transparent);
    }
    & when (@theme = variable) {
      .button-color(@borderActive; transparent; transparent);
    }
  }
  & when not (@border = transparent) {
    & when (@theme = dark) {
      .button-color(
        colorPalette('@{color}', 5); null; colorPalette('@{color}', 5)
      );
    }
    & when (not (@theme = dark) and not (@theme = variable)) {
      .button-color(
        colorPalette('@{color}', 7); null; colorPalette('@{color}', 7)
      );
    }
    & when (@theme = variable) {
      .button-color(@borderActive; transparent; @borderActive);
    }
  }
}

&-footer {
  display: flex;
  width: 100%;
  align-items: center;
  justify-content: space-around;
  font-size: 14px;
  line-height: 20px;
  color: @color-text-title;
  color: var(--am-card-action-color, @color-text-title);
  background: @color-fill-grey-inverse;
  background: var(--am-card-footer-color, @color-fill-grey-inverse);
  box-sizing: border-box;
  padding: @h-spacing-large;
  padding: var(--am-card-padding, @h-spacing-large);
  border-radius: 0 0 @corner-radius-lg @corner-radius-lg;
  border-radius: 0 0 var(--am-card-border-radius, @corner-radius-lg) var(--am-card-border-radius, @corner-radius-lg);
  border-top: @corner-radius-lg solid @color-fill-grey-inverse;
  border-top:
    var(--am-card-border-radius, @corner-radius-lg) solid
    var(--am-card-footer-color, @color-fill-grey-inverse);
  margin-top: -(@corner-radius-lg);
  margin-top: calc(var(--am-card-border-radius, @corner-radius-lg) * -1);
  z-index: 1;
}

& when not (@critical) {
    .product-item-name a:hover {
        text-decoration: underline;
    }
    .actions-secondary {
        .action {
            &:extend(.transition all);
            @media @media-hover {
                &:hover {
                    color: var(--secondary-link-hover-color);
                    background: var(--secondary-link-hover-bg);
                }
            }
            &::before {
                .lib-css(-webkit-mask-size, @listing-item-actions-secondary-icon__size);
            }
        }
    }
    & when (@listing-grid-item__zoom-on-hover) {
        :where(.products-grid, .widget-product-carousel) .product-item {
            .zoom-on-hover();
        }
    }
}

[class^="swatch-opt-"] {
    position: absolute;
    pointer-events: none;
    background: color-mix(
        in srgb,
        var(--swatches-abs-bg) ~"calc(var(--swatches-abs-bg-alpha) * 100%)",
        transparent
    );
    .lib-css(z-index, @listing-grid-item-swatches__absolute__z-index);
    .lib-css(top, @listing-grid-item-swatches__absolute__top);
    .lib-css(bottom, @listing-grid-item-swatches__absolute__bottom);
    .lib-css(left, @listing-grid-item-swatches__absolute__left);
    .lib-css(right, @listing-grid-item-swatches__absolute__right);
    .lib-css(padding, @listing-grid-item-swatches__absolute__padding);
    .lib-css(border, @listing-grid-item-swatches__absolute__border);
    .lib-css(border-radius, @listing-grid-item-swatches__absolute__border-radius);
    .lib-css(box-shadow, @listing-grid-item-swatches__absolute__box-shadow);
    margin: 0 !important;
    transform: translateY(50%);
    opacity: 0;
    &:extend(.transition all);
}

[data-content-type="tabs"] {
    .tab-header {
        &:extend(.breeze-tab-toggler-common all);
        &:extend(.breeze-tab-toggler-horizontal all);
        &.active {
            &:extend(.breeze-tab-toggler-common-active all);
            &:extend(.breeze-tab-toggler-horizontal-active all);
        }
        & when (@critical) {
            .padding(@tab-toggler__padding);
            .padding(@tab-toggler__horizontal__padding);
        }
    }
    .tabs-content {
        > div {
            &:extend(.breeze-tab-content-common all);
            &:extend(.breeze-tab-content-horizontal all);
            &[aria-hidden=false] {
                &:extend(.breeze-tab-content-common-active all);
            }
            & when (@critical) {
                .padding(@tab-content__horizontal__padding);
            }
        }
    }
}

@media only screen and (min-width: @computerBreakpoint) {
    & when (@variationSearchShort) {
        .ui.search.short > .results {
            max-height: @scrollingComputerMaxResultsHeight;
        }
        & when (@variationSearchVeryShort) {
            .ui.search[class*="very short"] > .results {
                max-height: @scrollingComputerMaxResultsHeight * 0.75;
            }
        }
    }
    & when (@variationSearchLong) {
        .ui.search.long > .results {
            max-height: @scrollingComputerMaxResultsHeight * 2;
        }
        & when (@variationSearchVeryLong) {
            .ui.search[class*="very long"] > .results {
                max-height: @scrollingComputerMaxResultsHeight * 3;
            }
        }
    }
}

@media only screen and (max-width: @largestMobileScreen) {
    & when (@variationSearchShort) {
        .ui.search.short > .results {
            max-height: @scrollingMobileMaxResultsHeight;
        }
        & when (@variationSearchVeryShort) {
            .ui.search[class*="very short"] > .results {
                max-height: @scrollingMobileMaxResultsHeight * 0.75;
            }
        }
    }
    & when (@variationSearchLong) {
        .ui.search.long > .results {
            max-height: @scrollingMobileMaxResultsHeight * 2;
        }
        & when (@variationSearchVeryLong) {
            .ui.search[class*="very long"] > .results {
                max-height: @scrollingMobileMaxResultsHeight * 3;
            }
        }
    }
}

@media only screen and (min-width: @tabletBreakpoint) {
    & when (@variationSearchShort) {
        .ui.search.short > .results {
            max-height: @scrollingTabletMaxResultsHeight;
        }
        & when (@variationSearchVeryShort) {
            .ui.search[class*="very short"] > .results {
                max-height: @scrollingTabletMaxResultsHeight * 0.75;
            }
        }
    }
    & when (@variationSearchLong) {
        .ui.search.long > .results {
            max-height: @scrollingTabletMaxResultsHeight * 2;
        }
        & when (@variationSearchVeryLong) {
            .ui.search[class*="very long"] > .results {
                max-height: @scrollingTabletMaxResultsHeight * 3;
            }
        }
    }
}

& when not (@variationIconColors = false) {
    each(@variationIconColors, {
        @color: @value;
        @c: @colors[@@color][color];
        @l: @colors[@@color][light];

        i.@{color}.icon.icon.icon.icon.icon.icon {
            color: @c;
        }
        & when (@variationIconInverted) {
            i.inverted.@{color}.icon.icon.icon.icon.icon.icon {
                color: @l;
            }
            & when (@variationIconBordered) or (@variationIconCircular) {
                i.inverted.bordered.@{color}.icon.icon.icon.icon.icon.icon,
                i.inverted.circular.@{color}.icon.icon.icon.icon.icon.icon,
                i.inverted.bordered.@{color}.icons,
                i.inverted.circular.@{color}.icons {
                    background-color: @c;
                    color: @white;
                }
            }
        }
    });
}

& when not (@variationSegmentColors = false) {
    each(@variationSegmentColors, {
        @color: @value;
        @c: @colors[@@color][color];
        & when not (@color=primary) and not (@color=secondary) {
            .ui.ui.ui.ui.ui.@{color}.segment@{notInverted} {
                border-top: @coloredBorderSize solid @c;
            }
            & when (@variationSegmentInverted) {
                .ui.ui.ui.ui.ui.inverted.@{color}.segment {
                    background-color: @c;
                    color: @white;
                    & when not (@variationSegmentPiled) and ((@variationSegmentAttached) or (@variationSegmentStacked)) {
                        border-color: c;
                    }
                }
                .ui.ui.inverted.@{color}.segment:not(.piled) when (@variationSegmentPiled) and ((@variationSegmentAttached) or (@variationSegmentStacked)) {
                    border-color: @c;
                }
            }
        }
    });
}

@media only screen and (min-width: @widescreenMonitorBreakpoint) {
    & when (@variationSearchShort) {
        .ui.search.short > .results {
            max-height: @scrollingWidescreenMaxResultsHeight;
        }
        & when (@variationSearchVeryShort) {
            .ui.search[class*="very short"] > .results {
                max-height: @scrollingWidescreenMaxResultsHeight * 0.75;
            }
        }
    }
    & when (@variationSearchLong) {
        .ui.search.long > .results {
            max-height: @scrollingWidescreenMaxResultsHeight * 2;
        }
        & when (@variationSearchVeryLong) {
            .ui.search[class*="very long"] > .results {
                max-height: @scrollingWidescreenMaxResultsHeight * 3;
            }
        }
    }
}

& when not (@variationMenuColors = false) {
    each(@variationMenuColors, {
        @color: @value;
        @c: @colors[@@color][color];
        @h: @colors[@@color][hover];

        & when not (@color=secondary) {
            .ui.ui.ui.inverted.menu .@{color}.active.item,
            .ui.ui.inverted.@{color}.menu {
                background-color: @c;
            }
            .ui.inverted.@{color}.menu .item::before {
                background-color: @invertedColoredDividerBackground;
            }
            .ui.ui.inverted.@{color}.menu .active.item {
                background-color: @invertedColoredActiveBackground;
            }
            & when (@variationMenuPointing) {
                .ui.inverted.pointing.@{color}.menu .active.item {
                    background-color: @h;
                }
            }
        }
    });
}

& when not (@variationInputColors = false) {
    each(@variationInputColors, {
        @color: @value;
        @c: @colors[@@color][color];
        @h: @colors[@@color][hover];

        input[type="file"].ui.@{color}.file.input::-webkit-file-upload-button,
        .ui.@{color}.file.input input[type="file"]::-webkit-file-upload-button {
            background: @c;
            color: @white;
            &:hover {
                background: @h;
            }
        }

        input[type="file"].ui.@{color}.file.input::file-selector-button,
        .ui.@{color}.file.input input[type="file"]::file-selector-button {
            background: @c;
            color: @white;
            &:hover {
                background: @h;
            }
        }
    });
}

& .ui.toast {
    & > .close.icon when (@variationToastClose) {
        cursor: pointer;
        margin: 0;
        opacity: @toastCloseOpacity;
        transition: @toastCloseTransition;
        &:hover {
            opacity: 1;
        }
    }
    &.vertical > .close.icon when (@variationToastVertical) and (@variationToastClose) {
        margin-top: -@toastCloseTopDistance;
        margin-right: -@toastCloseTopDistance;
    }
    &@{notVertical} > .close.icon when (@variationToastClose) {
        position: absolute;
        top: @toastCloseTopDistance;
        &:not(.left) {
            right: @toastCloseRightDistance;
        }
        &.left {
            margin-left: -@toastCloseRightDistance;
        }
    }
}

progress {
  -webkit-appearance: none;
  height: 8px;
  border-radius: @component-border-radius;
  background-color: @input-background-color;
  box-shadow: inset 0 0 0 1px @input-border-color;

  &::-webkit-progress-bar {
    background-color: transparent;
  }

  &::-webkit-progress-value {
    border-radius: @component-border-radius;
    background-color: @progress-background-color;
  }

  // Is buffering (when no value is set)
  &:indeterminate {
    background-image:
       linear-gradient(-45deg, transparent 33%, @progress-background-color 33%,
                               @progress-background-color 66%, transparent 66%);
    background-size: 24px 8px, 100% 100%, 100% 100%;
    -webkit-animation: progress-buffering 5s linear 6; // stop animation after 6 runs (30s) to limit CPU usage
  }
}

[data-page="admin-services-npc"] {
    div[id="cbid.npc.config.vkey"] {
        white-space: normal;

        input[id="widget.cbid.npc.config.vkey"][type="password"] {
            margin-top: 0;
            margin-bottom: 0;
        }

        .cbi-button {
            margin: 0;
            border: none;
        }
    }

    div[id^="cbid.npc."][id$=".server_addr"]:not([id="cbid.npc.config.server_addr"]),
    div[id^="cbid.npc."][id$=".vkey"]:not([id="cbid.npc.config.vkey"]),
    div[id^="cbid.npc."][id$=".protocol"]:not([id="cbid.npc.config.protocol"]),
    div[id^="cbid.npc."][id$=".dns"]:not([id="cbid.npc.config.dns"]) {
        +br {
            display: none;
        }
    }

    div.cbi-value.nowrap {
        white-space: normal;
    }
}

&-in-view&-range-hover-start:not(&-in-range):not(&-range-start):not(&-range-end),
    &-in-view&-range-hover-end:not(&-in-range):not(&-range-start):not(&-range-end),
    &-in-view&-range-hover-start&-range-start-single,
    &-in-view&-range-hover-start&-range-start&-range-end&-range-end-near-hover,
    &-in-view&-range-hover-end&-range-start&-range-end&-range-start-near-hover,
    &-in-view&-range-hover-end&-range-end-single,
    &-in-view&-range-hover:not(&-in-range) {
      &::after {
        position: absolute;
        top: 50%;
        z-index: 0;
        height: 24px;
        border-top: @border-width-base dashed @picker-date-hover-range-border-color;
        border-bottom: @border-width-base dashed @picker-date-hover-range-border-color;
        transform: translateY(-50%);
        transition: all @animation-duration-slow;
        content: '';
      }
    }

body > &, .framework7-root > & {
    opacity: 0;
    display: none;
    .transform(translate3d(0,0,0));
    &.photo-browser-in {
        display: block;
        .animation(photoBrowserIn 400ms forwards);
    }
    &.photo-browser-out {
        display: block;
        .animation(photoBrowserOut 400ms forwards);
    }
    html.with-statusbar-overlay & {
        height: ~"-webkit-calc(100% - 20px)";
        height: ~"calc(100% - 20px)";
        top: 20px;
    }
    html.with-statusbar-overlay.device-iphone-x & {
        height: ~"-webkit-calc(100% - constant(safe-area-inset-top))";
        height: ~"-webkit-calc(100% - env(safe-area-inset-top))";
        height: ~"calc(100% - constant(safe-area-inset-top))";
        height: ~"calc(100% - env(safe-area-inset-top))";
        top: constant(safe-area-inset-top);
        top: env(safe-area-inset-top);
    }
}

[data-colored-header=true] {
  .AvocadoHeader-authBtn--login {
    border-color: var(--header-color) !important;
    color: var(--header-color) !important;

    &:hover {
      background: color-mix(in srgb, var(--header-color) 15%, transparent) !important;
    }
  }

  .AvocadoHeader-authBtn--signup {
    background: var(--header-color) !important;
    // Text should contrast against --header-color (white on light, dark on dark).
    // --header-bg in colored mode equals the primary color — reuse it as text.
    color: var(--header-bg) !important;

    &:hover {
      opacity: 0.9 !important;
    }
  }

  // Separator "or" between the two buttons
  .AvocadoHeader-authSep {
    color: var(--header-color) !important;
    opacity: 0.75;
  }
}

span.ui-treetable-toggler {
    background-image: none !important;
    display: inline !important;

    &.ui-icon-triangle-1-e:before {
        font-family: 'Glyphicons Halflings';
        color: @admin-text-color;
        position: relative;
        font-size: @glyphicon-icon-size;
        font-weight: bold;
        top: -5px;
        padding: 0 4px;
        overflow: hidden;
        content: "\e258" !important;
    }

    &.ui-icon-triangle-1-s:before {
        font-family: 'Glyphicons Halflings';
        color: @admin-text-color;
        position: relative;
        font-size: @glyphicon-icon-size;
        font-weight: bold;
        padding: 0 4px;
        overflow: hidden;
        top: -5px;
        content: "\e259" !important;
    }
}

body div.ui-selectcheckboxmenu, div.ui-fluid div.ui-selectcheckboxmenu {

    &.ui-state-focus {
        -moz-box-shadow: 0 0 5px @box-shadow-color;
        -webkit-box-shadow: 0 0 5px @box-shadow-color;
        box-shadow: 0 0 5px @box-shadow-color;
        border-color: lighten(@box-shadow-color, 30%);
    }

    &.ui-state-error {
        border: 1px solid @box-shadow-color-error;
    }

    &.ui-state-error.ui-state-focus {
        -moz-box-shadow: 0 0 5px @box-shadow-color-error;
        -webkit-box-shadow: 0 0 5px @box-shadow-color-error;
        box-shadow: 0 0 5px @box-shadow-color-error;
        border: 1px solid @box-shadow-color-error;
    }

    .ui-selectcheckboxmenu-trigger.ui-state-error.ui-state-focus {
        border: none;
        box-shadow: none;
    }
}

img.mwe-math-fallback-image-display,
    img.mwe-math-fallback-image-inline {
      & when (@flavor = latte) {
        filter: brightness(0) saturate(100%) invert(31%) sepia(9%) saturate(
          1499%
        ) hue-rotate(196deg) brightness(90%) contrast(85%);
      }

      & when (@flavor = frappe) {
        filter: brightness(0) saturate(100%) invert(92%) sepia(6%) saturate(
          3753%
        ) hue-rotate(184deg) brightness(93%) contrast(106%);
      }

      & when (@flavor = macchiato) {
        filter: brightness(0) saturate(100%) invert(82%) sepia(7%) saturate(
          1042%
        ) hue-rotate(193deg) brightness(103%) contrast(92%);
      }

      & when (@flavor = mocha) {
        filter: brightness(0) saturate(100%) invert(83%) sepia(28%) saturate(
          223%
        ) hue-rotate(190deg) brightness(99%) contrast(93%);
      }
    }

@supports (backdrop-filter: blur(1px)) or (-webkit-backdrop-filter: blur(1px)) {
    .v-mask.left.v-backdrop-blurs {
        background: linear-gradient(90deg, @theme1 30%, fade(@theme1, @lgOpacity)), linear-gradient(0deg, fade(@theme1, 50%), transparent 50px, transparent);
    }
    .v-mask.right.v-backdrop-blurs {
        background: linear-gradient(270deg, @theme1 30%, fade(@theme1, @lgOpacity)), linear-gradient(0deg, fade(@theme1, 50%), transparent 50px, transparent);
    }
    .v-mask.top.v-backdrop-blurs {
        background: linear-gradient(180deg, @theme1 40%, fade(@theme1, 50%)), linear-gradient(0deg, fade(@theme1, 50%), transparent 50px, transparent);
    }
    .v-mask.bottom.v-backdrop-blurs {
        background: linear-gradient(0deg, @theme1 40%, fade(@theme1, @lgOpacity));
    }
    .v-mask.center.v-backdrop-blurs {
        background: radial-gradient(ellipse, @theme1 40%, fade(@theme1, @lgOpacity)), linear-gradient(0deg, fade(@theme1, 50%), transparent 50px, transparent);
    }
}

@media @phone {
  .DiscussionPage--skeleton {
    --disc-avatar: 34px;
    --disc-gap: 12px;

    .AvocadoSkeleton-heroInner { padding: 32px 20px 36px; }
    .AvocadoSkeleton-nav   { justify-content: center; }
    .AvocadoSkeleton-title { width: 85%; margin: 0 auto; }
    .AvocadoSkeleton-meta  { justify-content: center; }
    .AvocadoSkeleton-line--lg { height: 56px; }

    // Mobile posts: no side avatar, show inline avatar+username header row
    .AvocadoSkeleton-post         { display: block; padding: 18px 0; }
    .AvocadoSkeleton-postAvatar   { display: none; }
    .AvocadoSkeleton-postBody     { padding-top: 0; }
    .AvocadoSkeleton-line--user   { display: none; }
    .AvocadoSkeleton-postHeader   { display: flex; }

    // Nav skeleton hidden on phone (nav moves to header area on mobile)
    .Page-sidebar { display: none; }

    // Decoration icon skeleton hidden on phone (mirrors real hero behavior)
    .AvocadoSkeleton-decoContainer { display: none !important; }
  }
}

@media @tablet-up {
  .Page.DiscussionPage .PostUser-badges {
    position: absolute;
    left: calc(83px - var(--disc-avatar) - var(--disc-gap));
    white-space: nowrap;
    pointer-events: none;
  }

  // Quando fixed avatar está ativo, esconde o badges original do Post-header
  .Page.DiscussionPage .CommentPost--fixedAvatar .Post-header .PostUser-badges {
    display: none !important;
  }

  // Mostra apenas o clone dos badges que está em Post-side
  .Page.DiscussionPage .CommentPost--fixedAvatar .PostUser-badges--inSide {
    display: block !important;
    position: sticky;
    top: var(--avocado-avatar-sticky-top);
    left: auto;
    margin-left: calc(5px - var(--disc-avatar) - var(--disc-gap));
    align-self: start;
    white-space: nowrap;
    pointer-events: none;
  }
}
